public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        // Precompute popcount-depth for each number in nums
        long[] depthList = new long[nums.length];
        for (int i = 0; i < nums.length; i++) {
            depthList[i] = popcountDepth(nums[i]);
        }

        // Segment Tree implementation
        class SegmentTree {
            int size;
            List<Map<Long, Long>> tree;

            public SegmentTree(long[] data) {
                size = 1;
                while (size < data.length) {
                    size <<= 1;
                }
                tree = new ArrayList<>(2 * size);
                for (int i = 0; i < 2 * size; i++) {
                    tree.add(new HashMap<>());
                }
                // Fill the leaves
                for (int i = 0; i < data.length; i++) {
                    tree.set(size + i, Map.of(data[i], 1L));
                }
                // Build the tree
                for (int i = size - 1; i > 0; i--) {
                    for (Map.Entry<Long, Long> entry : tree.get(2 * i).entrySet()) {
                        tree.get(i).put(entry.getKey(), tree.get(i).getOrDefault(entry.getKey(), 0L) + entry.getValue());
                    }
                    for (Map.Entry<Long, Long> entry : tree.get(2 * i + 1).entrySet()) {
                        tree.get(i).put(entry.getKey(), tree.get(i).getOrDefault(entry.getKey(), 0L) + entry.getValue());
                    }
                }
            }

            public void update(int pos, long oldVal, long newVal) {
                pos += size;
                tree.set(pos, Map.of(newVal, 1L));
                tree.set(pos, Map.of(newVal, 1L));
                pos >>= 1;
                while (pos >= 1) {
                    Map<Long, Long> left = tree.get(2 * pos);
                    Map<Long, Long> right = tree.get(2 * pos + 1);
                    Map<Long, Long> parent = tree.get(pos);
                    for (Map.Entry<Long, Long> entry : left.entrySet()) {
                        parent.put(entry.getKey(), parent.getOrDefault(entry.getKey(), 0L) + entry.getValue());
                    }
                    for (Map.Entry<Long, Long> entry : right.entrySet()) {
                        parent.put(entry.getKey(), parent.getOrDefault(entry.getKey(), 0L) + entry.getValue());
                    }
                    pos >>= 1;
                }
            }

            public long query(int l, int r, long k) {
                long res = 0;
                l += size;
                r += size;
                while (l <= r) {
                    if (l % 2 == 1) {
                        for (Map.Entry<Long, Long> entry : tree.get(l).entrySet()) {
                            if (entry.getKey() == k) {
                                res += entry.getValue();
                            }
                        }
                        l++;
                    }
                    if (r % 2 == 0) {
                        for (Map.Entry<Long, Long> entry : tree.get(r).entrySet()) {
                            if (entry.getKey() == k) {
                                res += entry.getValue();
                            }
                        }
                        r--;
                    }
                    l >>= 1;
                    r >>= 1;
                }
                return res;
            }
        }

        SegmentTree st = new SegmentTree(depthList);
        long[] answer = new long[queries.length];
        for (int i = 0; i < queries.length; i++) {
            if (queries[i][0] == 1) {
                int l = (int) queries[i][1];
                int r = (int) queries[i][2];
                long k = queries[i][3];
                answer[i] = st.query(l, r, k);
            } else {
                int idx = (int) queries[i][1];
                long val = queries[i][2];
                long oldVal = depthList[idx];
                long newVal = popcountDepth(val);
                depthList[idx] = newVal;
                st.update(idx, oldVal, newVal);
            }
        }
        return answer;
    }

    private static long popcountDepth(long x) {
        long depth = 0;
        while (x > 0) {
            x = Long.bitCount(x);
            depth++;
            if (x == 1) {
                break;
            }
        }
        return depth;
    }
